// Set dynamic date ranges for current and previous week
// GSC has ~3 day data delay for 'final' data — end date is 3 days ago
const now = new Date();

const endDate = new Date(now);
endDate.setDate(endDate.getDate() - 3);

const startDate = new Date(endDate);
startDate.setDate(startDate.getDate() - 6);

const prevEndDate = new Date(startDate);
prevEndDate.setDate(prevEndDate.getDate() - 1);

const prevStartDate = new Date(prevEndDate);
prevStartDate.setDate(prevStartDate.getDate() - 6);

const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    startDate: fmt(startDate),
    endDate: fmt(endDate),
    prevStartDate: fmt(prevStartDate),
    prevEndDate: fmt(prevEndDate),
    weekEnding: fmt(endDate)
  }
}];

// Pull data from all three API nodes
const datesData = $('Set Dates').first().json;
const currentKwData = $('Fetch Current Keywords').first().json;
const currentPgData = $('Fetch Current Pages').first().json;
const prevKwData = $('Fetch Previous Keywords').first().json;

const currentKeywords = currentKwData.rows || [];
const currentPages = currentPgData.rows || [];
const prevKeywords = prevKwData.rows || [];

// Build previous week lookup map
const prevMap = {};
for (const row of prevKeywords) {
  const kw = row.keys[0];
  prevMap[kw] = { clicks: row.clicks, impressions: row.impressions, position: row.position };
}

// Process current keywords — calculate changes and apply flags
const flaggedRows = [];
const keywordRows = [];

for (const row of currentKeywords) {
  const kw = row.keys[0];
  const prev = prevMap[kw] || { clicks: 0, impressions: 0, position: null };

  const clickChange = row.clicks - prev.clicks;
  const impressionChange = row.impressions - prev.impressions;
  const posChange = prev.position !== null ? parseFloat((prev.position - row.position).toFixed(1)) : null;

  const flags = [];

  if (posChange !== null && Math.abs(posChange) > 3) {
    const f = posChange > 0 ? 'IMPROVED' : 'DROPPED';
    flags.push(f);
    flaggedRows.push([datesData.weekEnding, 'keyword', kw, f, row.position.toFixed(1), prev.position.toFixed(1)]);
  }

  if (row.impressions > 100 && row.ctr < 0.01) {
    flags.push('LOW CTR');
    flaggedRows.push([datesData.weekEnding, 'keyword', kw, 'LOW CTR', (row.ctr * 100).toFixed(2) + '%', '']);
  }

  if (prev.position !== null && prev.position > 10 && row.position <= 10) {
    flags.push('PAGE 1 ENTRY');
    flaggedRows.push([datesData.weekEnding, 'keyword', kw, 'PAGE 1 ENTRY', row.position.toFixed(1), prev.position.toFixed(1)]);
  } else if (prev.position !== null && prev.position <= 10 && row.position > 10) {
    flags.push('PAGE 1 EXIT');
    flaggedRows.push([datesData.weekEnding, 'keyword', kw, 'PAGE 1 EXIT', row.position.toFixed(1), prev.position.toFixed(1)]);
  }

  keywordRows.push([
    kw,
    row.clicks,
    row.impressions,
    (row.ctr * 100).toFixed(2) + '%',
    row.position.toFixed(1),
    clickChange >= 0 ? '+' + clickChange : String(clickChange),
    impressionChange >= 0 ? '+' + impressionChange : String(impressionChange),
    posChange !== null ? (posChange >= 0 ? '+' + posChange : String(posChange)) : 'N/A',
    flags.join(', ')
  ]);
}

// Sort keywords by impressions descending
keywordRows.sort((a, b) => Number(b[2]) - Number(a[2]));

// Process pages — sort by clicks descending
const pageRows = (currentPages).map(row => [
  row.keys[0],
  row.clicks,
  row.impressions,
  (row.ctr * 100).toFixed(2) + '%',
  row.position.toFixed(1),
  ''
]);
pageRows.sort((a, b) => Number(b[1]) - Number(a[1]));

// Totals for history tab
const totalClicks = currentKeywords.reduce((s, r) => s + r.clicks, 0);
const totalImpressions = currentKeywords.reduce((s, r) => s + r.impressions, 0);
const totalClicksPrev = prevKeywords.reduce((s, r) => s + r.clicks, 0);
const overallCtr = totalImpressions > 0 ? ((totalClicks / totalImpressions) * 100).toFixed(2) + '%' : '0%';
const avgPos = currentKeywords.length > 0
  ? (currentKeywords.reduce((s, r) => s + r.position, 0) / currentKeywords.length).toFixed(1)
  : 'N/A';
const topKeyword = keywordRows.length > 0 ? keywordRows[0][0] : '';
const topPage = pageRows.length > 0 ? pageRows[0][0] : '';

const historyRow = [[datesData.weekEnding, totalClicks, totalImpressions, overallCtr, avgPos, topKeyword, topPage]];

// Click change percentage
const clickChangePct = totalClicksPrev > 0
  ? ((totalClicks - totalClicksPrev) / totalClicksPrev * 100).toFixed(1)
  : 'N/A';
const clickDir = clickChangePct !== 'N/A'
  ? (parseFloat(clickChangePct) >= 0 ? '+' : '') + clickChangePct + '%'
  : 'first run — no comparison data yet';

// Build summary text for email
const top5kw = keywordRows.slice(0, 5).map(r => `  ${r[0]}: ${r[1]} clicks, pos ${r[4]}`).join('\n');
const top5pg = pageRows.slice(0, 5).map(r => `  ${r[0]}: ${r[1]} clicks`).join('\n');
const flagSummary = flaggedRows.length > 0
  ? flaggedRows.map(r => `  [${r[3]}] ${r[2]}${r[5] ? ' — was pos ' + r[5] + ', now ' + r[4] : ' — ' + r[4]}`).join('\n')
  : '  No significant movements this week.';

const summaryText = `SEO Weekly Snapshot — week ending ${datesData.weekEnding}\n\nOVERVIEW\nClicks: ${totalClicks} (${clickDir} vs last week)\nImpressions: ${totalImpressions}\nCTR: ${overallCtr}\nAvg position: ${avgPos}\n\nTOP 5 KEYWORDS\n${top5kw}\n\nTOP 5 PAGES\n${top5pg}\n\nFLAGGED MOVEMENTS (${flaggedRows.length})\n${flagSummary}\n\nFull data: https://docs.google.com/spreadsheets/d/1Q2s49XED4TnyM4Fv9QVTjwyH-p9vXg89wCBHbL9fyy0`;

// Build seo-current-data.md content
const top10kw = keywordRows.slice(0, 10).map(r =>
  `| ${r[0]} | ${r[1]} | ${r[2]} | ${r[3]} | ${r[4]} | ${r[8] || '-'} |`
).join('\n');
const top10pg = pageRows.slice(0, 10).map(r =>
  `| ${r[0]} | ${r[1]} | ${r[2]} | ${r[3]} | ${r[4]} |`
).join('\n');
const flagTable = flaggedRows.length > 0
  ? flaggedRows.map(r => `| ${r[0]} | ${r[1]} | ${r[2]} | ${r[3]} | ${r[4]} | ${r[5]} |`).join('\n')
  : '| — | — | No flags this week | — | — | — |';

const seoContextContent = `---\nname: SEO Current Data\ndescription: Live weekly Search Console data — top keywords, pages, flagged movements. Auto-generated every Monday.\ntype: reference\nlast_updated: ${datesData.weekEnding}\nwarning: Do not edit manually. Overwritten every Monday by N8N pipeline.\n---\n\n# SEO Weekly Data — week ending ${datesData.weekEnding}\n\n> Operator instruction: paste this file into any SEO agent context before assigning an SEO task. If last_updated is more than 7 days old — stop. Flag to Hadi that the pipeline may not have run.\n\n## Overview\n\n| Metric | This week | vs Last week |\n|--------|-----------|-------------|\n| Clicks | ${totalClicks} | ${clickDir} |\n| Impressions | ${totalImpressions} | — |\n| CTR | ${overallCtr} | — |\n| Avg Position | ${avgPos} | — |\n\n## Top 10 Keywords by Impressions\n\n| Keyword | Clicks | Impressions | CTR | Avg Position | Flag |\n|---------|--------|-------------|-----|-------------|------|\n${top10kw}\n\n## Top 10 Pages by Clicks\n\n| Page | Clicks | Impressions | CTR | Avg Position |\n|------|--------|-------------|-----|-------------|\n${top10pg}\n\n## Flagged Movements This Week\n\n| Date | Type | Item | Flag | Current | Previous |\n|------|------|------|------|---------|----------|\n${flagTable}\n\n## Full Data\n[Google Sheet — Hadi Photography SEO Weekly Data](https://docs.google.com/spreadsheets/d/1Q2s49XED4TnyM4Fv9QVTjwyH-p9vXg89wCBHbL9fyy0)\n`;

// Build Sheets API payloads (passed directly as HTTP request bodies)
const keywordsPayload = { values: keywordRows.length > 0 ? keywordRows : [['No data this week']] };
const pagesPayload = { values: pageRows.length > 0 ? pageRows : [['No data this week']] };
const historyPayload = { values: historyRow };
const flaggedPayload = flaggedRows.length > 0 ? { values: flaggedRows } : null;

return [{
  json: {
    weekEnding: datesData.weekEnding,
    keywordsPayload,
    pagesPayload,
    historyPayload,
    flaggedPayload,
    hasFlaggedItems: flaggedRows.length > 0,
    summaryText,
    seoContextContent
  }
}];

// Prepare GitHub file update payload
// Base64 encode the seo-current-data.md content
const content = $('Process All Data').first().json.seoContextContent;
const encoded = Buffer.from(content).toString('base64');
const weekEnding = $('Process All Data').first().json.weekEnding;

return [{
  json: {
    encodedContent: encoded,
    commitMessage: `SEO data update — week ending ${weekEnding}`
  }
}];

// Resolve SHA for GitHub PUT
// If the file exists, GitHub GET returns { sha: '...' }
// If the file does not exist (404 with neverError), sha is undefined
// GitHub requires SHA when updating an existing file
// GitHub requires NO sha field (or omit it) when creating a new file
const getResponse = $input.first().json;
const sha = getResponse.sha || null;

const payload = $('Prepare GitHub Payload').first().json;

const body = {
  message: payload.commitMessage,
  content: payload.encodedContent
};

if (sha) {
  body.sha = sha;
}

return [{ json: { body: JSON.stringify(body) } }];
